using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Shared state – the notebook the agent writes into
// ---------------------------------------------------------------------------
var notebook = new Notebook();

// ---------------------------------------------------------------------------
// Build the AI chat client with automatic function-invocation
// ---------------------------------------------------------------------------
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(openAiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Register tools the agent can call
// ---------------------------------------------------------------------------
var searchTool = new SearchTool();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(searchTool.SearchWeb),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.ReadNotes),
    ],
};

// ---------------------------------------------------------------------------
// Prompt the user for a research topic
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided – exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching \"{topic}\" …\n");

// ---------------------------------------------------------------------------
// Run the agent loop
// ---------------------------------------------------------------------------
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research assistant. The user will give you a topic.
        1. Use the SearchWeb tool (multiple queries if needed) to find information.
        2. Use AddNote to save every important fact you discover.
        3. After you have gathered enough information, use ReadNotes to review
           everything, then write a concise, well-structured summary for the user.
        Always cite the source URL when saving a note.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
};

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("── Research Summary ─────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────────────────");

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Provides web search capabilities using DuckDuckGo.</summary>
sealed class SearchTool
{
    private readonly HttpClient _http = new();

    [Description("Search the web for a query and return a list of result snippets with URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var html = await _http.SendAsync(request)
                .ContinueWith(t => t.Result.Content.ReadAsStringAsync())
                .Unwrap();

            var results = ParseResults(html);

            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            foreach (var r in results.Take(6))
                sb.AppendLine($"- {r.Title}\n  {r.Snippet}\n  URL: {r.Url}\n");

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseResults(string html)
    {
        var results = new List<SearchResult>();

        // Match DuckDuckGo HTML result blocks
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]+href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);
        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (int i = 0; i < Math.Min(links.Count, snippets.Count); i++)
        {
            var rawUrl = WebUtility.HtmlDecode(links[i].Groups[1].Value);
            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var uddg = Regex.Match(rawUrl, @"[?&]uddg=([^&]+)");
            var finalUrl = uddg.Success
                ? WebUtility.UrlDecode(uddg.Groups[1].Value)
                : rawUrl;

            results.Add(new SearchResult
            {
                Title = StripHtml(links[i].Groups[2].Value),
                Snippet = StripHtml(snippets[i].Groups[1].Value),
                Url = finalUrl,
            });
        }

        return results;
    }

    private static string StripHtml(string s) =>
        WebUtility.HtmlDecode(Regex.Replace(s, "<.*?>", "")).Trim();

    private sealed class SearchResult
    {
        public string Title { get; init; } = "";
        public string Snippet { get; init; } = "";
        public string Url { get; init; } = "";
    }
}

/// <summary>An in-memory notebook the agent uses to collect research notes.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save an important fact or finding. Include the source URL.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Read back all notes collected so far.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");

        Console.WriteLine($"  📖 Reading {_notes.Count} note(s)");
        return sb.ToString();
    }
}

